-- =====================================================================
-- SEED DATA: MODULE 7 - HỒ SƠ BỆNH NHÂN (PATIENTS)
-- =====================================================================
-- Thứ tự chạy: SAU 01, 01b, 02, 03, 04, 05, 06, 06b
-- Bao gồm: patients (150 hồ sơ gắn với 150 tài khoản bệnh nhân)
-- =====================================================================

BEGIN;

-- *********************************************************************
-- HỒ SƠ BỆNH NHÂN (PATIENTS) - 150 bệnh nhân
-- Gắn account_id với tài khoản USR_PAT_001 → USR_PAT_150
-- patient_code: BN-YYMM-XXXX (Mã bệnh nhân tự sinh)
-- *********************************************************************

-- *********************************************************************
-- NGƯỜI THÂN / LIÊN HỆ KHẨN CẤP (PATIENT_CONTACTS)
-- Mỗi bệnh nhân có 1-2 người liên hệ
-- *********************************************************************

-- *********************************************************************
-- BẢO HIỂM BỆNH NHÂN (PATIENT_INSURANCES)
-- ~120 BN có BHYT, ~30 BN có thêm BH tư nhân
-- Số thẻ BHYT: HS4079XXXXXXXXX (format chuẩn BHXH VN)
-- *********************************************************************

-- *********************************************************************
-- TIỀN SỬ BỆNH LÝ (PATIENT_MEDICAL_HISTORIES)
-- ~60 bệnh nhân có tiền sử bệnh (40%), mỗi BN 1-3 bệnh lý
-- history_type: PERSONAL (bản thân), FAMILY (gia đình)
-- Mã bệnh theo ICD-10
-- *********************************************************************

-- *********************************************************************
-- DỊ ỨNG & TÁC DỤNG PHỤ (PATIENT_ALLERGIES)
-- ~45 bệnh nhân có dị ứng (30%), mỗi BN 1-2 dị ứng
-- allergen_type: DRUG, FOOD, ENVIRONMENT, LATEX, CHEMICAL
-- severity: MILD, MODERATE, SEVERE
-- *********************************************************************

-- *********************************************************************
-- GẮN THẺ BỆNH NHÂN (PATIENT_TAGS)
-- ~60 bệnh nhân có thẻ (40%), mỗi BN 1-3 thẻ
-- Thẻ phải phù hợp với tình trạng BN (bệnh mãn, dị ứng, BH, tuổi)
-- *********************************************************************

COMMIT;

-- =====================================================================
-- THỐNG KÊ SEED DATA MODULE 7 - HỒ SƠ BỆNH NHÂN
-- =====================================================================
-- patients:            150 hồ sơ bệnh nhân
-- patient_contacts:    200 người liên hệ khẩn cấp / thân nhân
-- patient_insurances:  140 thẻ bảo hiểm (120 BHYT + 20 BH tư nhân)
-- medical_histories:   100 tiền sử bệnh lý (~60 BN, 40%)
-- patient_allergies:   57 dị ứng (~45 BN, 30%)
-- patient_tags:        346 thẻ gắn bệnh nhân
-- TỔNG:                993 bản ghi
-- =====================================================================